mapper.select:
/* wms-inventory-openorder-qty-sql-oracle.xml - selectOpenOrderQty - 가용재고(오픈오더) 조회 SQL */ SELECT IC.ICKEY /* 상품코드 */ , COALESCE(IV.AVQTY, 0) + COALESCE(OB.OBEXPCTQTY, 0) AS TOTQTY /* 총수량 */ , COALESCE(IV.AVQTY, 0) AS AVQTY /* 가용수량 */ , COALESCE(OB.OBEXPCTQTY, 0) AS OBEXPCTQTY /* 출고예정수량 */ FROM (
SELECT #{ickey} AS ICKEY
) IC LEFT OUTER JOIN ( SELECT IVLC.CTKEY , IVLC.OWKEY , IVLC.ICKEY , SUM(IVLC.TOTQTY) AS TOTQTY , SUM(CASE WHEN ( IC.EXPCKYN = 'N' OR (IC.EXPCKYN = 'Y' AND TO_CHAR(TO_DATE(SUBSTR(IVAT.EXPDATE,1,8),'YYYYMMDD') - IC.EXPCNVRSNDAYS::INTEGER + ROUND((IC.EXPCNVRSNDAYS * (OBIMPSCRITRT/100)),0)::INTEGER,'YYYYMMDD') >= TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD'))) THEN IVLC.AVQTY ELSE 0 END) AS AVQTY FROM TWORK_INFO_IVATXLC IVLC INNER JOIN TWORK_MST_LC LC ON IVLC.CTKEY = LC.CTKEY AND IVLC.LCKEY = LC.LCKEY INNER JOIN TWORK_MST_ZN ZN ON LC.CTKEY = ZN.CTKEY AND LC.ZNKEY = ZN.ZNKEY INNER JOIN TWORK_INFO_IVAT IVAT ON IVLC.CTKEY = IVAT.CTKEY AND IVLC.OWKEY = IVAT.OWKEY AND IVLC.IVATKEY = IVAT.IVATKEY INNER JOIN TWORK_MST_IC IC ON IVLC.CTKEY = IC.CTKEY AND IVLC.OWKEY = IC.OWKEY AND IVLC.ICKEY = IC.ICKEY WHERE IVLC.CTKEY = #{ctkey} AND IVLC.OWKEY = #{owkey} AND LC.LCTYPECD = '90' /* 로케이션유형코드 - 보관 */ AND ZN.ZNTYPECD = '10' /* 존유형코드 - 보관존 */ AND IVLC.ICKEY IN
#{ickey}
GROUP BY IVLC.CTKEY , IVLC.OWKEY , IVLC.ICKEY ) IV ON IC.ICKEY = IV.ICKEY LEFT OUTER JOIN ( SELECT CTKEY , OWKEY , ICKEY , SUM(EXPCTQTY) AS OBEXPCTQTY FROM TWORK_INFO_OB_DT WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND ICKEY IN
#{ickey}
AND ALQTY = 0 AND OBDTSTATUSCD = '00' /* 오픈오더 수량은 작업상태가 최초 생성인 주문만 포함 */ GROUP BY CTKEY , OWKEY , ICKEY ) OB ON IV.CTKEY = OB.CTKEY AND IV.OWKEY = OB.OWKEY AND IV.ICKEY = OB.ICKEY
